      // Estado para o histórico de arquivos gerados
      const [historicoArquivos, setHistoricoArquivos] = useState([]);
    // Função para salvar uma linha no array de linhas
    function handleSalvarLinha() {
      if (!ano || !origem || !destino || !idEnlace || !meio || !cnpj) return;
      const novaLinha = { ano, origem, destino, idEnlace, meio, cnpj };
      setLinhas(prev => {
        const novas = [...prev, novaLinha];
        localStorage.setItem(formStorageKey, JSON.stringify({ ano: '', origem: '', destino: '', idEnlace: '', meio: '', cnpj: '' }));
        setAno('2024');
        setOrigem('');
        setDestino('');
        setIdEnlace('');
        setMeio('');
        setCnpj('');
        return novas;
      });
    }
